+package org.apache.doris.planner.external;
+
+import org.apache.doris.common.Config;
+
+import org.apache.hadoop.fs.Path;
+import org.apache.hadoop.mapred.FileSplit;
+import org.junit.Assert;
+import org.junit.Test;
+
+import java.lang.reflect.Constructor;
+import java.lang.reflect.Field;
+import java.lang.reflect.Method;
+
+public class FileSplitStrategyTriggerTest {
+    @Test
+    public void fileSplitStrategyStartsNewRangeWhenSizeLimitIsExceeded() throws Exception {
+        Field splitSizeField = Config.class.getDeclaredField("file_scan_node_split_size");
+        Field splitNumField = Config.class.getDeclaredField("file_scan_node_split_num");
+        long oldSplitSize = splitSizeField.getLong(null);
+        long oldSplitNum = splitNumField.getLong(null);
+        try {
+            splitSizeField.setLong(null, 10L);
+            splitNumField.setLong(null, 1000L);
+
+            Class<?> strategyClass = Class.forName(ExternalFileScanNode.class.getName() + "$FileSplitStrategy");
+            Constructor<?> constructor = strategyClass.getDeclaredConstructor();
+            constructor.setAccessible(true);
+            Object strategy = constructor.newInstance();
+
+            Method hasNext = strategyClass.getDeclaredMethod("hasNext");
+            Method update = strategyClass.getDeclaredMethod("update", FileSplit.class);
+            Method next = strategyClass.getDeclaredMethod("next");
+            hasNext.setAccessible(true);
+            update.setAccessible(true);
+            next.setAccessible(true);
+
+            Assert.assertFalse((Boolean) hasNext.invoke(strategy));
+            update.invoke(strategy, new FileSplit(new Path("file:///tmp/large-file.orc"), 0, 11, new String[0]));
+            Assert.assertTrue((Boolean) hasNext.invoke(strategy));
+            next.invoke(strategy);
+            Assert.assertFalse((Boolean) hasNext.invoke(strategy));
+        } finally {
+            splitSizeField.setLong(null, oldSplitSize);
+            splitNumField.setLong(null, oldSplitNum);
+        }
+    }
+}
